(()=>{var e=document.getElementById("tagFilter"),t=document.querySelectorAll(".post-entry");e&&t.length>0&&e.addEventListener("click",n=>{const s=n.target.closest("button[data-tag]");if(!s)return;const o=s.dataset.tag;e.querySelectorAll("button[data-tag]").forEach(e=>{e.classList.toggle("active",e===s)}),t.forEach(e=>{const t=e.dataset.tags?e.dataset.tags.split(","):[];!o||t.includes(o)?e.style.display="":e.style.display="none"})})})()